//! Bowl-filtered attention prune — chaos-engine variant.
//!
//! Replaces the median-shift binary drop in `inference_ffi.rs:384-440`
//! with a bowl Q-filter that damps below-cutoff positions instead of
//! zeroing them. Mirrors `bowl_mesh::BowlMeshHead` semantics from
//! `open-source/gnosis/distributed-inference/src/bowl_mesh.rs`, but
//! lives here as a standalone primitive so the chaos crate does NOT
//! grow a `distributed-inference` dep.
//!
//! ## Why
//!
//! Hard-zeroing below-cutoff positions removes their contribution
//! from the residual sum, which is the failure mode formalized in
//! `Gnosis/BowlMeshNode.lean::mask_at_high_damping`: the binary mask
//! is the *high-damping limit* of a TaoBowl, not its only regime.
//! Zero-filling off-resonance dims corrupts the cross-layer residual
//! sum `h_{n+1} = h_n + f(h_n)` because the next layer still reads
//! the zeroed slots. The bowl Q-filter damps the below-cutoff tail
//! by `(damping + 1)` instead of zeroing it — keeping the
//! cross-layer add intact.
//!
//! ## Z accounting (load-bearing correctness story)
//!
//! The original code's `z_kept` was sum-of-kept-exps and renormalized
//! out_head by `1/z_kept`. That implicitly assumes the dropped tail
//! contributes zero — i.e. the binary mask. With the bowl filter we
//! split the partition:
//!
//!   - `z_kept`   = Σ exps[t] over t with scores[t] > cutoff
//!   - `z_damped` = Σ exps[t] / (damping + 1) over t with scores[t] ≤ cutoff
//!
//! Total z = `z_kept + z_damped`. Renormalization uses the TOTAL,
//! and each damped position contributes `(exps[t] / (damping+1)) / z_total`
//! to `out_head`. This preserves the softmax invariant
//! (Σ weights = 1) AND keeps the residual sum non-degenerate, because
//! every position still contributes a non-zero amount unless damping
//! is so large the f32 rounds to zero (the high-damping mask regime).
//!
//! ## Status
//!
//! NOT YET wired into `inference_ffi.rs`. Caller opts in by invoking
//! `bowl_filtered_attention_prune` directly. Integration into the
//! existing `forward_chaos` path is a separate follow-up.

#![allow(dead_code)]

/// Configuration for the bowl attention prune. Defaults mirror the
/// `balancedBowl` Lean witness (rim=5, void=5, rigidity=3, damping=1)
/// from `gnosis-math/Gnosis/BowlMeshRuntimeOracle.lean`.
#[derive(Debug, Clone, Copy)]
pub struct BowlPruneConfig {
    pub rim: u32,
    pub void: u32,
    pub rigidity: u32,
    pub damping: u32,
}

impl Default for BowlPruneConfig {
    fn default() -> Self {
        Self {
            rim: 5,
            void: 5,
            rigidity: 3,
            damping: 1,
        }
    }
}

impl BowlPruneConfig {
    /// Mirror of `BowlMeshHead::q_factor` from
    /// `distributed-inference/src/bowl_mesh.rs`:
    ///   `if damping = 0 then 0 else (rim * rigidity) / damping`
    /// Zero damping returns 0 as a finite sentinel — matches the Lean
    /// `qFactor` definition's `damping = 0` case.
    pub fn q_factor(&self) -> u32 {
        if self.damping == 0 {
            0
        } else {
            self.rim.saturating_mul(self.rigidity) / self.damping
        }
    }

    /// Damping divisor used on the softmax mass of below-cutoff
    /// positions. Equals `damping + 1` so `damping = 0` is a
    /// pass-through (matches the bowl off-resonance branch
    /// `amp / (damping + 1)` in `BowlMeshHead::q_filter`).
    fn damp_divisor(&self) -> f32 {
        self.damping as f32 + 1.0
    }
}

/// Result of a bowl-filtered prune: per-head output + normalization
/// terms. `z_kept + z_damped` is the total partition function the
/// output was renormalized by.
#[derive(Debug, Clone)]
pub struct BowlPruneOutput {
    pub out_head: Vec<f32>,
    pub z_kept: f32,
    pub z_damped: f32,
    pub kept_positions: usize,
    pub damped_positions: usize,
}

impl BowlPruneOutput {
    fn empty() -> Self {
        Self {
            out_head: Vec::new(),
            z_kept: 0.0,
            z_damped: 0.0,
            kept_positions: 0,
            damped_positions: 0,
        }
    }

    /// Total partition mass used for renormalization.
    pub fn z_total(&self) -> f32 {
        self.z_kept + self.z_damped
    }
}

/// Bowl-filtered attention prune over a single head's score / value
/// columns.
///
/// `scores[t]` is the pre-softmax attention score at position `t`.
/// `values[t]` is the value vector for that position (length
/// `head_dim`, must be uniform across `t`). `cutoff` is the threshold
/// below which positions are damped rather than zeroed (callers can
/// compute it as the median, as the original code did, via
/// [`median_cutoff`], or use a different policy).
///
/// The output `out_head` has length equal to `values[0].len()` (or 0
/// if `values` is empty). Each entry is the bowl-weighted sum over
/// positions, normalized by `z_kept + z_damped`. The softmax
/// invariant (Σ weights = 1) holds within f32 tolerance.
///
/// Edge cases (no panics):
///   - `scores.len() == 0` → returns empty `BowlPruneOutput`.
///   - `values.len() != scores.len()` → returns empty (length
///     mismatch is a caller bug; we do not silently truncate or
///     mis-pair).
///   - `values` non-empty but `values[0].len() == 0` → returns a
///     zero-length `out_head` with valid z accounting.
pub fn bowl_filtered_attention_prune(
    scores: &[f32],
    values: &[Vec<f32>],
    cutoff: f32,
    cfg: BowlPruneConfig,
) -> BowlPruneOutput {
    let seq_len = scores.len();
    if seq_len == 0 || values.len() != seq_len {
        return BowlPruneOutput::empty();
    }
    let head_dim = values[0].len();
    let mut out = BowlPruneOutput {
        out_head: vec![0.0f32; head_dim],
        z_kept: 0.0,
        z_damped: 0.0,
        kept_positions: 0,
        damped_positions: 0,
    };

    // 1. Numerically stable softmax: subtract max before exp.
    let mut max_score = f32::NEG_INFINITY;
    for &s in scores {
        if s > max_score {
            max_score = s;
        }
    }
    if !max_score.is_finite() {
        return out;
    }

    // 2. exps[t] = exp(scores[t] - max_score)
    let mut exps: Vec<f32> = Vec::with_capacity(seq_len);
    for &s in scores {
        exps.push((s - max_score).exp());
    }

    // 3. Partition into kept / damped, accumulating z_kept and
    //    z_damped. Damped softmax mass is exps[t] / (damping + 1) —
    //    the bowl off-resonance branch applied to mass, not value.
    let divisor = cfg.damp_divisor();
    let inv_divisor = 1.0f32 / divisor;
    for t in 0..seq_len {
        if values[t].len() != head_dim {
            // Ragged values: caller bug. Bail with empty output rather
            // than panicking or silently mis-summing.
            return BowlPruneOutput::empty();
        }
        if scores[t] > cutoff {
            out.z_kept += exps[t];
            out.kept_positions += 1;
        } else {
            out.z_damped += exps[t] * inv_divisor;
            out.damped_positions += 1;
        }
    }

    // 4. Renormalize by total z. If z_total is zero (all exps
    //    underflowed), return zeros — no panic.
    let z_total = out.z_total();
    if z_total <= 0.0 || !z_total.is_finite() {
        return out;
    }
    let inv_z = 1.0f32 / z_total;

    // 5. Weighted sum over positions. Kept positions contribute
    //    exps[t] * inv_z; damped positions contribute
    //    (exps[t] * inv_divisor) * inv_z. Every position contributes
    //    something non-zero (modulo f32 underflow) — that is the
    //    cross-layer-residual-preserving property.
    for t in 0..seq_len {
        let mass = if scores[t] > cutoff {
            exps[t]
        } else {
            exps[t] * inv_divisor
        };
        let w = mass * inv_z;
        if w == 0.0 {
            continue;
        }
        for d in 0..head_dim {
            out.out_head[d] += w * values[t][d];
        }
    }

    out
}

/// Median-cutoff convenience: matches the policy used in the
/// original `inference_ffi.rs` (lines 384 ff.). Returns 0.0 for an
/// empty slice (no panic). For even-length slices, returns the mean
/// of the two middle elements; for odd-length, the middle element.
pub fn median_cutoff(scores: &[f32]) -> f32 {
    if scores.is_empty() {
        return 0.0;
    }
    let mut sorted: Vec<f32> = scores.to_vec();
    sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
    let n = sorted.len();
    if n % 2 == 1 {
        sorted[n / 2]
    } else {
        0.5 * (sorted[n / 2 - 1] + sorted[n / 2])
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Helper: build trivial 1-d values so out_head[0] reads as a
    /// scalar weighted sum, easy to reason about.
    fn scalar_values(xs: &[f32]) -> Vec<Vec<f32>> {
        xs.iter().map(|&x| vec![x]).collect()
    }

    /// Degenerate bowl (damping=0) is a pass-through: below-cutoff
    /// positions contribute their full `exp*value / z_total` to the
    /// sum, with `divisor = 1`. Per the Lean theorem
    /// `BowlMeshNode::mask_at_high_damping`, damping=0 is the
    /// OPPOSITE end of the regime spectrum from the binary mask —
    /// no attenuation of off-resonance positions at all.
    #[test]
    fn damping_zero_passes_through_below_cutoff() {
        let cfg = BowlPruneConfig {
            rim: 5,
            void: 5,
            rigidity: 3,
            damping: 0,
        };
        let scores = vec![0.0, 0.0]; // equal scores → equal exps
        let values = scalar_values(&[1.0, 3.0]);
        // cutoff between them so position 0 is damped, position 1 is kept.
        // But scores are equal, so make cutoff strictly below both for "all kept"
        // OR strictly between by perturbing — here use distinct scores.
        let scores = vec![-1.0, 1.0];
        let values = scalar_values(&[1.0, 3.0]);
        let cutoff = 0.0; // position 0 damped, position 1 kept
        let out = bowl_filtered_attention_prune(&scores, &values, cutoff, cfg);
        // With damping=0, divisor=1: damped mass = exps[0]*1 = exps[0],
        // so z_damped + z_kept = z_full. Output is the FULL softmax over both.
        assert_eq!(out.kept_positions, 1);
        assert_eq!(out.damped_positions, 1);
        // Reference full softmax:
        let e0 = (-1.0f32 - 1.0).exp(); // exp(score-max)
        let e1 = (1.0f32 - 1.0).exp();
        let z = e0 + e1;
        let expected = (e0 * 1.0 + e1 * 3.0) / z;
        assert!(
            (out.out_head[0] - expected).abs() < 1e-5,
            "damping=0 must reproduce full softmax: got {} want {}",
            out.out_head[0],
            expected
        );
    }

    /// damping=1 → divisor=2 → below-cutoff exps are halved in the
    /// partition mass. Matches the bowl off-resonance branch
    /// `amp / (damping+1)` from `BowlMeshHead::q_filter`.
    #[test]
    fn damping_one_halves_below_cutoff() {
        let cfg = BowlPruneConfig {
            damping: 1,
            ..Default::default()
        };
        let scores = vec![-1.0, 1.0];
        let values = scalar_values(&[1.0, 3.0]);
        let cutoff = 0.0;
        let out = bowl_filtered_attention_prune(&scores, &values, cutoff, cfg);
        let e0 = (-1.0f32 - 1.0).exp();
        let e1 = 1.0f32;
        let damped_mass = e0 * 0.5;
        let kept_mass = e1;
        let z = damped_mass + kept_mass;
        let expected = (damped_mass * 1.0 + kept_mass * 3.0) / z;
        assert!(
            (out.z_damped - damped_mass).abs() < 1e-6,
            "z_damped: got {} want {}",
            out.z_damped,
            damped_mass
        );
        assert!(
            (out.z_kept - kept_mass).abs() < 1e-6,
            "z_kept: got {} want {}",
            out.z_kept,
            kept_mass
        );
        assert!(
            (out.out_head[0] - expected).abs() < 1e-5,
            "halved bowl mix: got {} want {}",
            out.out_head[0],
            expected
        );
    }

    /// damping=99 → divisor=100 → below-cutoff exps are ~1/100,
    /// approximating the binary-mask regime (Lean:
    /// `BowlMeshNode.mask_at_high_damping`). The damped contribution
    /// should be negligible relative to kept.
    #[test]
    fn high_damping_approximates_binary_mask() {
        let cfg = BowlPruneConfig {
            damping: 99,
            ..Default::default()
        };
        let scores = vec![0.0, 0.0];
        let values = scalar_values(&[1.0, 3.0]);
        // Cutoff splits them: equal scores tie-break by the strict `>` in
        // the implementation. With equal scores both go to damped — change
        // scores so position 1 is strictly above cutoff.
        let scores = vec![0.0, 1.0];
        let values = scalar_values(&[1.0, 3.0]);
        let cutoff = 0.5;
        let out = bowl_filtered_attention_prune(&scores, &values, cutoff, cfg);
        // damped contribution ratio vs kept must be ~1/100 at this damping
        // level (modulo the exp() amplitude difference between the two scores).
        let ratio = out.z_damped / out.z_kept;
        let raw_exp_ratio = ((0.0f32 - 1.0).exp()) / 1.0f32;
        let expected_ratio = raw_exp_ratio / 100.0;
        assert!(
            (ratio - expected_ratio).abs() < 1e-5,
            "high-damping z_damped/z_kept: got {} want ~{}",
            ratio,
            expected_ratio
        );
        // And the output is dominated by the kept value (3.0) — not pulled
        // toward 1.0 as it would be with damping=0.
        assert!(
            out.out_head[0] > 2.9,
            "high damping must push output toward kept value 3.0, got {}",
            out.out_head[0]
        );
    }

    /// Partition-sum invariant: `z_total == z_kept + z_damped`
    /// exactly (the field is just the sum), and the contributions
    /// from the two regimes add up to the full normalized mass.
    #[test]
    fn z_total_equals_sum_of_z_kept_and_z_damped() {
        let cfg = BowlPruneConfig::default();
        let scores = vec![-2.0, -1.0, 0.5, 1.5, 3.0];
        let values = scalar_values(&[0.0, 1.0, 2.0, 3.0, 4.0]);
        let cutoff = median_cutoff(&scores);
        let out = bowl_filtered_attention_prune(&scores, &values, cutoff, cfg);
        assert!(
            (out.z_total() - (out.z_kept + out.z_damped)).abs() < 1e-7,
            "z_total accessor must equal field sum"
        );
        assert!(
            out.z_kept > 0.0,
            "median split must keep at least one position"
        );
        assert!(
            out.z_damped > 0.0,
            "median split must damp at least one position"
        );
        assert_eq!(out.kept_positions + out.damped_positions, scores.len());
    }

    /// Sum of effective softmax weights over positions equals 1.0
    /// within f32 tolerance — the softmax invariant survives the
    /// kept/damped partition because we renormalize by z_total.
    #[test]
    fn output_renormalization_preserves_unit_softmax() {
        let cfg = BowlPruneConfig::default();
        let scores = vec![-1.5, -0.5, 0.0, 0.7, 2.0];
        // Use one-hot per-position values so out_head[t] = weight[t].
        let mut values: Vec<Vec<f32>> = Vec::new();
        for t in 0..scores.len() {
            let mut v = vec![0.0f32; scores.len()];
            v[t] = 1.0;
            values.push(v);
        }
        let cutoff = median_cutoff(&scores);
        let out = bowl_filtered_attention_prune(&scores, &values, cutoff, cfg);
        let sum: f32 = out.out_head.iter().sum();
        assert!(
            (sum - 1.0).abs() < 1e-5,
            "softmax invariant: weights must sum to 1.0, got {}",
            sum
        );
        // No weight is exactly zero (every position contributes — the
        // residual-preserving property).
        for (t, &w) in out.out_head.iter().enumerate() {
            assert!(
                w > 0.0,
                "position {} contributed zero (binary-mask leak)",
                t
            );
        }
    }

    /// median_cutoff matches the naive definition for odd-length
    /// (middle element) and even-length (mean of two middle
    /// elements). Mirrors the median policy used by the original
    /// inference_ffi.rs path.
    #[test]
    fn median_cutoff_matches_naive_definition() {
        let odd = vec![3.0f32, 1.0, 2.0];
        assert_eq!(median_cutoff(&odd), 2.0);
        let even = vec![4.0f32, 2.0, 1.0, 3.0];
        assert_eq!(median_cutoff(&even), 2.5);
        let empty: Vec<f32> = Vec::new();
        assert_eq!(median_cutoff(&empty), 0.0, "no panic on empty");
        let single = vec![7.0f32];
        assert_eq!(median_cutoff(&single), 7.0);
    }

    /// Lean runtime-oracle parity: the `BowlPruneConfig` default
    /// (= balancedBowl: rim=5, void=5, rigidity=3, damping=1) must
    /// produce `q_factor = 15`, matching contract #1's intermediate
    /// `qFactor` value from `BowlMeshRuntimeOracle.lean` (used in the
    /// `10 * 15 = 150` on-resonance computation). Same numeric pin as
    /// `bowl_mesh.rs::tests::q_filter_on_resonance_amplifies`.
    #[test]
    fn runtime_oracle_pentad_parity() {
        let cfg = BowlPruneConfig::default();
        assert_eq!(cfg.q_factor(), 15, "balancedBowl Q must be 15 (Lean pin)");
        // Damping=0 sentinel: q_factor = 0 (mirrors Lean qFactor
        // damping=0 branch).
        let dead = BowlPruneConfig {
            damping: 0,
            ..Default::default()
        };
        assert_eq!(
            dead.q_factor(),
            0,
            "damping=0 must yield q_factor=0 sentinel"
        );
    }

    /// Edge case: empty input does not panic and returns an empty,
    /// zero-mass output.
    #[test]
    fn empty_scores_no_panic() {
        let out = bowl_filtered_attention_prune(
            &[],
            &Vec::<Vec<f32>>::new(),
            0.0,
            BowlPruneConfig::default(),
        );
        assert!(out.out_head.is_empty());
        assert_eq!(out.z_kept, 0.0);
        assert_eq!(out.z_damped, 0.0);
        assert_eq!(out.kept_positions, 0);
        assert_eq!(out.damped_positions, 0);
    }
}
